INSERT INTO kb_flow_edge (`id`, `workspace_id`, `bot_id`, `source_node_uuid`, `target_node_uuid`, `source_handle`, `style`, `valid_flag`, `del_flag`, `create_by`, `creator_id`, `create_time`, `update_by`, `updater_id`, `update_time`, `remark`) VALUES (68, 1001, 7, '1', 'llm-1774493047231', NULL, '{\"id\":\"e-1-source-llm-1774493047231-target-1774493047232-1\",\"type\":\"default\",\"source\":\"1\",\"target\":\"llm-1774493047231\",\"data\":{},\"events\":{},\"label\":\"\",\"style\":{\"stroke\":\"#999\",\"strokeWidth\":2},\"markerEnd\":{\"type\":\"arrowclosed\",\"width\":12,\"height\":12,\"color\":\"#999\"},\"sourceNode\":{\"id\":\"1\",\"type\":\"start\",\"dimensions\":{\"width\":200,\"height\":220},\"computedPosition\":{\"x\":120,\"y\":160,\"z\":0},\"handleBounds\":{\"source\":[{\"type\":\"source\",\"nodeId\":\"1\",\"position\":\"right\",\"x\":194,\"y\":105,\"width\":10,\"height\":10}],\"target\":[{\"type\":\"target\",\"nodeId\":\"1\",\"position\":\"left\",\"x\":-4,\"y\":105,\"width\":10,\"height\":10}]},\"selected\":false,\"dragging\":false,\"resizing\":false,\"initialized\":false,\"isParent\":false,\"position\":{\"x\":120,\"y\":160},\"data\":{\"input\":[{\"id\":\"text-1774493066647-1\",\"type\":\"text\",\"name\":\"context\",\"label\":\"待抽取内容\",\"maxLength\":2000,\"defaultValue\":\"\",\"required\":true},{\"id\":\"text-1774493470207-4\",\"type\":\"text\",\"name\":\"entityCallWord\",\"label\":\"要抽取的实体\",\"maxLength\":48,\"defaultValue\":\"\",\"required\":true},{\"id\":\"text-1774493525671-7\",\"type\":\"text\",\"name\":\"entityAttribute\",\"label\":\"实体属性\",\"maxLength\":48,\"defaultValue\":\"\",\"required\":true},{\"id\":\"text-1774493567783-12\",\"type\":\"text\",\"name\":\"relationCallWord\",\"label\":\"要抽取的关系\",\"maxLength\":48,\"defaultValue\":\"\",\"required\":true}],\"config\":{\"label\":\"开始\",\"description\":\"\"},\"output\":[]},\"events\":{}},\"targetNode\":{\"id\":\"llm-1774493047231\",\"type\":\"llm\",\"dimensions\":{\"width\":200,\"height\":119},\"computedPosition\":{\"x\":560,\"y\":200,\"z\":1000},\"handleBounds\":{\"source\":[{\"type\":\"source\",\"nodeId\":\"llm-1774493047231\",\"position\":\"right\",\"x\":194,\"y\":54.5,\"width\":10,\"height\":10}],\"target\":[{\"type\":\"target\",\"nodeId\":\"llm-1774493047231\",\"position\":\"left\",\"x\":-4,\"y\":54.5,\"width\":10,\"height\":10}]},\"selected\":true,\"dragging\":false,\"resizing\":false,\"initialized\":false,\"isParent\":false,\"position\":{\"x\":560,\"y\":200},\"data\":{\"input\":[],\"config\":{\"label\":\"LLM\",\"description\":\"添加描述...\",\"provider\":1,\"model\":\"qwen-max\",\"prompt\":\"角色定位：你是专业的知识图谱构建工程师，需严格遵循以下指令，从输入文本中精准抽取实体与关系，输出结构化结果。\\n一、核心任务（按优先级执行）\\n1. 实体抽取（必须完成）\\n实体类型限制：仅从输入文本中识别属于 [{{ node_1.entityCallWord }}] 的实体，类型需严格匹配预设列表，无额外扩展。\\n实体属性要求：每个实体需满足以下属性约束定义的属性要求，无预设属性时需保留 属性 键（值可为空）。\\n```json\\n{{ node_1.entityAttribute }}\\n```\\n            \\n实体片段要求：每个实体的 片段 需为文本中 直接描述该实体的原句，需完整且具有独立语义，不得拆分或修改。\\n输出格式：\\n```json\\n{\\n    \\\"实体文本\\\": \\\"【实体名称】\\\",\\n    \\\"实体类型\\\": \\\"【实体类型】\\\",\\n    \\\"片段\\\": \\\"【实体描述原句】\\\",\\n    \\\"属性\\\": {\\n    \\\"属性名1\\\": \\\"属性值1\\\",\\n    \\\"属性名2\\\": \\\"属性值2\\\"\\n    }\\n}\\n```\\n2. 关系抽取（基于实体的因果关联）\\n关系类型限制：仅使用 [{{ node_1.relationCallWord }}] 中的关系，不得新增或替换。\\n关系逻辑约束：仅提取文本中 明确存在的因果关联（如「疾病引起症状」「症状表现为某现象」），不得进行推理或联想。\\n关系三元组要求：\\n关系类型需严格匹配预设列表（如 引起「表现出」）；\\n头实体与尾实体必须是 不同名称，且均在 entities 中存在；\\n关系需满足「实体类型约束」（如：疾病→引起→症状）；\\n忽略无关系的实体（即仅保留有对应关系的实体）。\\n输出格式：\\n```json\\n{\\n    \\\"头实体\\\": \\\"【实体文本】\\\",\\n    \\\"关系\\\": \\\"【关系类型】\\\",\\n    \\\"尾实体\\\": \\\"【实体文本】\\\"\\n}\\n```\\n3. 结果去重与校验（最终输出前处理）\\n重复去重：对 relations 中的三元组进行去重，仅保留唯一的「头实体 + 关系 + 尾实体」组合；\\n结果过滤：\\n仅保留输入文本中 明确出现 的实体与关系，无则返回空数组；\\n忽略「头实体与尾实体名称相同」「头尾实体不在 entities 中」「不在预定义 Schema 中的实体 / 关系」；\\n关系三元组需满足「头尾实体类型匹配」「无重复」「无逻辑冲突」。\\n二、约束条件（必须严格遵守）\\n禁止推理联想：仅基于文本中的明确信息抽取，不得添加未提及的内容（如「糖尿病会导致高血压」需文本中明确出现「糖尿病引起高血压」，否则不得抽取）；\\n实体完整性：实体需完整且具有独立语义，不得拆分或合并（如「慢性阻塞性肺疾病（COPD）」需保留完整名称）；\\n关系合法性：关系三元组需满足「头实体与尾实体不同名」「类型匹配」「存在于 entities 中」；\\n输出格式：最终结果需为 JSON 数组格式，无额外冗余文本（如「结果如下：」「提取到的实体是：」等）。\\n三、输入与输出规范\\n1. 输入\\n文本内容：\\n{{ node_1.context }}\\n输出示例\\n```json\\n{\\n    \\\"entities\\\": [\\n    {\\n        \\\"实体文本\\\": \\\"爱因斯坦\\\",\\n        \\\"实体类型\\\": \\\"人物\\\",\\n        \\\"片段\\\": \\\"爱因斯坦是个伟大的人物。\\\",\\n        \\\"属性\\\": {\\n        \\\"性别\\\": \\\"男\\\",\\n        \\\"年龄\\\": \\\"42\\\"\\n        }\\n    },\\n    {\\n        \\\"实体文本\\\": \\\"相对论\\\",\\n        \\\"实体类型\\\": \\\"理论\\\",\\n        \\\"片段\\\": \\\"他创作的《相对论》震惊全世界。\\\",\\n        \\\"属性\\\": {\\n        \\\"提出者\\\": \\\"爱因斯坦\\\"\\n        }\\n    }\\n    ],\\n    \\\"relations\\\": [\\n    {\\n        \\\"头实体\\\": \\\"爱因斯坦\\\",\\n        \\\"关系\\\": \\\"提出\\\",\\n        \\\"尾实体\\\": \\\"相对论\\\"\\n    }\\n    ]\\n}\\n```\\n四、异常处理\\n若输入文本中无符合预设 Schema 的实体或关系，直接返回空数组（{\\\"entities\\\": [], \\\"relations\\\": []}）；\\n若实体或关系存在逻辑冲突（如「头实体与尾实体名称相同」），需忽略该三元组。\",\"temperature\":1,\"maxTokens\":4096,\"topP\":1,\"logprobs\":false,\"topLogprobs\":0,\"frequencyPenalty\":0,\"responseFormat\":\"\",\"stopSequences\":\"\",\"memoryEnabled\":false,\"visionEnabled\":false,\"reasoningTagEnabled\":false,\"structuredOutputEnabled\":false,\"retryEnabled\":false,\"errorStrategy\":\"none\"},\"output\":[{\"variableKey\":\"text\",\"variableLabel\":\"text\",\"valueType\":\"string\",\"path\":\"text\"}]},\"events\":{}},\"sourceX\":324,\"sourceY\":270,\"targetX\":556,\"targetY\":259.5}', 1, 0, '超级管理员', 1, '2026-03-26 13:39:23', '超级管理员', NULL, '2026-03-26 13:39:23', NULL);
INSERT INTO kb_flow_edge (`id`, `workspace_id`, `bot_id`, `source_node_uuid`, `target_node_uuid`, `source_handle`, `style`, `valid_flag`, `del_flag`, `create_by`, `creator_id`, `create_time`, `update_by`, `updater_id`, `update_time`, `remark`) VALUES (69, 1001, 7, 'llm-1774493047231', 'reply-1774493051863', NULL, '{\"id\":\"e-llm-1774493047231-source-reply-1774493051863-target-1774493051864-2\",\"type\":\"default\",\"source\":\"llm-1774493047231\",\"target\":\"reply-1774493051863\",\"data\":{},\"events\":{},\"label\":\"\",\"style\":{\"stroke\":\"#999\",\"strokeWidth\":2},\"markerEnd\":{\"type\":\"arrowclosed\",\"width\":12,\"height\":12,\"color\":\"#999\"},\"sourceNode\":{\"id\":\"llm-1774493047231\",\"type\":\"llm\",\"dimensions\":{\"width\":200,\"height\":119},\"computedPosition\":{\"x\":560,\"y\":200,\"z\":1000},\"handleBounds\":{\"source\":[{\"type\":\"source\",\"nodeId\":\"llm-1774493047231\",\"position\":\"right\",\"x\":194,\"y\":54.5,\"width\":10,\"height\":10}],\"target\":[{\"type\":\"target\",\"nodeId\":\"llm-1774493047231\",\"position\":\"left\",\"x\":-4,\"y\":54.5,\"width\":10,\"height\":10}]},\"selected\":true,\"dragging\":false,\"resizing\":false,\"initialized\":false,\"isParent\":false,\"position\":{\"x\":560,\"y\":200},\"data\":{\"input\":[],\"config\":{\"label\":\"LLM\",\"description\":\"添加描述...\",\"provider\":1,\"model\":\"qwen-max\",\"prompt\":\"角色定位：你是专业的知识图谱构建工程师，需严格遵循以下指令，从输入文本中精准抽取实体与关系，输出结构化结果。\\n一、核心任务（按优先级执行）\\n1. 实体抽取（必须完成）\\n实体类型限制：仅从输入文本中识别属于 [{{ node_1.entityCallWord }}] 的实体，类型需严格匹配预设列表，无额外扩展。\\n实体属性要求：每个实体需满足以下属性约束定义的属性要求，无预设属性时需保留 属性 键（值可为空）。\\n```json\\n{{ node_1.entityAttribute }}\\n```\\n            \\n实体片段要求：每个实体的 片段 需为文本中 直接描述该实体的原句，需完整且具有独立语义，不得拆分或修改。\\n输出格式：\\n```json\\n{\\n    \\\"实体文本\\\": \\\"【实体名称】\\\",\\n    \\\"实体类型\\\": \\\"【实体类型】\\\",\\n    \\\"片段\\\": \\\"【实体描述原句】\\\",\\n    \\\"属性\\\": {\\n    \\\"属性名1\\\": \\\"属性值1\\\",\\n    \\\"属性名2\\\": \\\"属性值2\\\"\\n    }\\n}\\n```\\n2. 关系抽取（基于实体的因果关联）\\n关系类型限制：仅使用 [{{ node_1.relationCallWord }}] 中的关系，不得新增或替换。\\n关系逻辑约束：仅提取文本中 明确存在的因果关联（如「疾病引起症状」「症状表现为某现象」），不得进行推理或联想。\\n关系三元组要求：\\n关系类型需严格匹配预设列表（如 引起「表现出」）；\\n头实体与尾实体必须是 不同名称，且均在 entities 中存在；\\n关系需满足「实体类型约束」（如：疾病→引起→症状）；\\n忽略无关系的实体（即仅保留有对应关系的实体）。\\n输出格式：\\n```json\\n{\\n    \\\"头实体\\\": \\\"【实体文本】\\\",\\n    \\\"关系\\\": \\\"【关系类型】\\\",\\n    \\\"尾实体\\\": \\\"【实体文本】\\\"\\n}\\n```\\n3. 结果去重与校验（最终输出前处理）\\n重复去重：对 relations 中的三元组进行去重，仅保留唯一的「头实体 + 关系 + 尾实体」组合；\\n结果过滤：\\n仅保留输入文本中 明确出现 的实体与关系，无则返回空数组；\\n忽略「头实体与尾实体名称相同」「头尾实体不在 entities 中」「不在预定义 Schema 中的实体 / 关系」；\\n关系三元组需满足「头尾实体类型匹配」「无重复」「无逻辑冲突」。\\n二、约束条件（必须严格遵守）\\n禁止推理联想：仅基于文本中的明确信息抽取，不得添加未提及的内容（如「糖尿病会导致高血压」需文本中明确出现「糖尿病引起高血压」，否则不得抽取）；\\n实体完整性：实体需完整且具有独立语义，不得拆分或合并（如「慢性阻塞性肺疾病（COPD）」需保留完整名称）；\\n关系合法性：关系三元组需满足「头实体与尾实体不同名」「类型匹配」「存在于 entities 中」；\\n输出格式：最终结果需为 JSON 数组格式，无额外冗余文本（如「结果如下：」「提取到的实体是：」等）。\\n三、输入与输出规范\\n1. 输入\\n文本内容：\\n{{ node_1.context }}\\n输出示例\\n```json\\n{\\n    \\\"entities\\\": [\\n    {\\n        \\\"实体文本\\\": \\\"爱因斯坦\\\",\\n        \\\"实体类型\\\": \\\"人物\\\",\\n        \\\"片段\\\": \\\"爱因斯坦是个伟大的人物。\\\",\\n        \\\"属性\\\": {\\n        \\\"性别\\\": \\\"男\\\",\\n        \\\"年龄\\\": \\\"42\\\"\\n        }\\n    },\\n    {\\n        \\\"实体文本\\\": \\\"相对论\\\",\\n        \\\"实体类型\\\": \\\"理论\\\",\\n        \\\"片段\\\": \\\"他创作的《相对论》震惊全世界。\\\",\\n        \\\"属性\\\": {\\n        \\\"提出者\\\": \\\"爱因斯坦\\\"\\n        }\\n    }\\n    ],\\n    \\\"relations\\\": [\\n    {\\n        \\\"头实体\\\": \\\"爱因斯坦\\\",\\n        \\\"关系\\\": \\\"提出\\\",\\n        \\\"尾实体\\\": \\\"相对论\\\"\\n    }\\n    ]\\n}\\n```\\n四、异常处理\\n若输入文本中无符合预设 Schema 的实体或关系，直接返回空数组（{\\\"entities\\\": [], \\\"relations\\\": []}）；\\n若实体或关系存在逻辑冲突（如「头实体与尾实体名称相同」），需忽略该三元组。\",\"temperature\":1,\"maxTokens\":4096,\"topP\":1,\"logprobs\":false,\"topLogprobs\":0,\"frequencyPenalty\":0,\"responseFormat\":\"\",\"stopSequences\":\"\",\"memoryEnabled\":false,\"visionEnabled\":false,\"reasoningTagEnabled\":false,\"structuredOutputEnabled\":false,\"retryEnabled\":false,\"errorStrategy\":\"none\"},\"outpu